import { useNavigate } from "react-router-dom";
import { useState } from "react";

const Register = ({ role }) => {
  const navigate = useNavigate();
  const [formData, setFormData] = useState({
    username: "",
    password: "",
    confirmPassword: "",
    email: "",
  });

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData({ ...formData, [name]: value });
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    if (formData.password !== formData.confirmPassword) {
      alert("Passwords do not match!");
      return;
    }
    console.log(`${role} registered with`, formData);
    navigate(`/${role.toLowerCase().replace(" ", "")}/login`);
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-green-100">
      <div className="w-full max-w-md bg-white p-8 rounded shadow border border-green-300">
        <h2 className="text-2xl font-bold mb-2 text-center text-green-700">Register</h2>
        <p className="text-center text-sm mb-6 text-green-600">
          Masukkan Username dan Password untuk Register
        </p>
        <form onSubmit={handleSubmit} className="space-y-4">
          <div>
            <label htmlFor="username" className="block mb-1 text-green-800 font-medium">
              Username
            </label>
            <input
              id="username"
              type="text"
              name="username"
              value={formData.username}
              onChange={handleChange}
              className="w-full p-2 border border-green-600 rounded focus:outline-none"
              required
            />
          </div>

          <div>
            <label htmlFor="email" className="block mb-1 text-green-800 font-medium">
              Email
            </label>
            <input
              id="email"
              type="email"
              name="email"
              value={formData.email}
              onChange={handleChange}
              className="w-full p-2 border border-green-600 rounded focus:outline-none"
              required
            />
          </div>

          <div>
            <label htmlFor="password" className="block mb-1 text-green-800 font-medium">
              Password
            </label>
            <input
              id="password"
              type="password"
              name="password"
              value={formData.password}
              onChange={handleChange}
              className="w-full p-2 border border-green-600 rounded focus:outline-none"
              required
            />
          </div>

          <div>
            <label htmlFor="confirmPassword" className="block mb-1 text-green-800 font-medium">
              Re-enter Password
            </label>
            <input
              id="confirmPassword"
              type="password"
              name="confirmPassword"
              value={formData.confirmPassword}
              onChange={handleChange}
              className="w-full p-2 border border-green-600 rounded focus:outline-none"
              required
            />
          </div>

          <button
            type="submit"
            className="w-full bg-green-600 text-white p-2 rounded hover:bg-green-700 border border-green-700"
          >
            Register
          </button>
        </form>

        <div className="text-center mt-4">
          <span className="text-sm text-green-700">Sudah punya akun? </span>
          <a
            href={`/${role.toLowerCase().replace(" ", "")}/login`}
            className="text-green-700 hover:underline text-sm font-semibold"
          >
            Login
          </a>
        </div>
      </div>
    </div>
  );
};

export default Register;
